// 排版页眉页脚：小五号字体，页码居中阿拉伯数字，页眉线单细线
var doc = Application.ActiveDocument;
var sections = doc.Sections;
var result = { headerCount: 0, footerCount: 0, pageNumbers: 0 };

for (var i = 0; i < sections.Count; i++) {
    var section = sections.Item(i);

    // 处理页眉
    if (section.Headers.Count > 0) {
        var header = section.Headers.Item(0); // wdHeaderFooterPrimary = 0
        var headerRange = header.Range;
        headerRange.Font.NameCN = "宋体";
        headerRange.Font.Size = 9; // 小五号

        // 设置页眉线为单细线
        section.PageSetup.HeaderDistance = 1.5 * 28.35 / 2.54; // 1.5cm 转换为英寸
        section.PageSetup.HeaderLine = true; // 显示页眉线

        result.headerCount++;
    }

    // 处理页脚和页码
    if (section.Footers.Count > 0) {
        var footer = section.Footers.Item(0); // wdHeaderFooterPrimary = 0
        var footerRange = footer.Range;
        footerRange.Font.NameCN = "宋体";
        footerRange.Font.Size = 9; // 小五号

        // 插入居中页码（阿拉伯数字）
        footerRange.Fields.Add(footerRange.Start, 0, "", "", false, false); // wdFieldPage = 0
        var pageNumRange = footerRange.Fields.Item(0).Result;
        pageNumRange.ParagraphFormat.Alignment = 1; // wdAlignParagraphCenter = 1

        result.footerCount++;
        result.pageNumbers++;
    }
}

return result;

// 排版页眉页脚：小五号字体，页码居中阿拉伯数字，页眉线单细线
var doc = Application.ActiveDocument;
var sections = doc.Sections;
var result = { headerCount: 0, footerCount: 0, pageNumbers: 0 };

for (var i = 0; i < sections.Count; i++) {
    var section = sections.Item(i);

    // 处理页眉
    try {
        if (section.Headers && section.Headers.Count > 0) {
            var header = section.Headers.Item(0);
            var headerRange = header.Range;
            headerRange.Font.NameCN = "宋体";
            headerRange.Font.Size = 9;

            // 设置页眉线为单细线
            section.PageSetup.HeaderDistance = 1.5 * 28.35 / 2.54;
            section.PageSetup.HeaderLine = true;

            result.headerCount++;
        }
    } catch (e) {
        // 忽略错误
    }

    // 处理页脚和页码
    try {
        if (section.Footers && section.Footers.Count > 0) {
            var footer = section.Footers.Item(0);
            var footerRange = footer.Range;
            footerRange.Font.NameCN = "宋体";
            footerRange.Font.Size = 9;

            // 清除原有内容并插入页码
            footerRange.Text = "";
            footerRange.Fields.Add(footerRange.Start, 0, "", "", false, false);

            // 设置页码居中
            footerRange.ParagraphFormat.Alignment = 1;

            result.footerCount++;
            result.pageNumbers++;
        }
    } catch (e) {
        // 忽略错误
    }
}

return result;

// 检查文档结构并排版页眉页脚
var doc = Application.ActiveDocument;
var sections = doc.Sections;
var result = { sectionCount: sections.Count, headerCount: 0, footerCount: 0 };

// 遍历所有节
for (var i = 0; i < sections.Count; i++) {
    var section = sections.Item(i);

    // 尝试访问页眉
    try {
        var headers = section.Headers;
        if (headers && headers.Count > 0) {
            for (var h = 0; h < headers.Count; h++) {
                var header = headers.Item(h);
                var headerRange = header.Range;
                headerRange.Font.NameCN = "宋体";
                headerRange.Font.Size = 9;
                result.headerCount++;
            }
        }
    } catch (e) {
        result.sectionDetails = result.sectionDetails || [];
        result.sectionDetails.push({ index: i, error: "Header error: " + e.message });
    }

    // 尝试访问页脚
    try {
        var footers = section.Footers;
        if (footers && footers.Count > 0) {
            for (var f = 0; f < footers.Count; f++) {
                var footer = footers.Item(f);
                var footerRange = footer.Range;
                footerRange.Font.NameCN = "宋体";
                footerRange.Font.Size = 9;

                // 插入页码
                footerRange.Text = "";
                footerRange.Fields.Add(footerRange.Start, 0, "", "", false, false);
                footerRange.ParagraphFormat.Alignment = 1;

                result.footerCount++;
            }
        }
    } catch (e) {
        result.sectionDetails = result.sectionDetails || [];
        result.sectionDetails.push({ index: i, error: "Footer error: " + e.message });
    }
}

return result;

